# Terminal hard tier tasks — 10 tasks
# Format: task_name|prompt
# Tests: advanced terminal/debugging skills (race detector, benchmarking, deadlock analysis, HTTP debugging, flaky tests, goroutine leaks)
# Each task provides BROKEN code inline. The agent writes it, runs the appropriate tool, diagnoses the problem, fixes it, and verifies.

race-detector-fix|Work in /tmp/training-race-fix/. Run: mkdir -p /tmp/training-race-fix && cd /tmp/training-race-fix && go mod init training/race-fix. Write counter.go: package main; type Counter struct { n int }; func (c *Counter) Inc() { c.n++ }; func (c *Counter) Val() int { return c.n }. Write counter_test.go: package main; import ("sync"; "testing"); func TestRace(t *testing.T) { c := &Counter{}; var wg sync.WaitGroup; for i := 0; i < 100; i++ { wg.Add(1); go func() { defer wg.Done(); c.Inc() }() }; wg.Wait(); if c.Val() != 100 { t.Fatalf("got %d", c.Val()) } }. Run go test -race ./... — it will report a DATA RACE. Read the race report. Fix counter.go by adding a sync.Mutex to protect n in both Inc and Val. Run go test -race ./... to confirm the race is gone and the test passes. Report the race report output and final clean output.

benchmark-and-optimize|Work in /tmp/training-bench-opt/. Run: mkdir -p /tmp/training-bench-opt && cd /tmp/training-bench-opt && go mod init training/bench-opt. Write slow.go: package main; func ContainsStr(haystack []string, needle string) bool { for _, s := range haystack { if s == needle { return true } }; return false }; func BuildIndex(items []string) map[string]bool { idx := map[string]bool{}; for _, s := range items { idx[s] = true }; return idx }; func ContainsFast(idx map[string]bool, needle string) bool { return idx[needle] }. Write bench_test.go: package main; import "testing"; var data = func() []string { s := make([]string, 10000); for i := range s { s[i] = string(rune('a'+i%26)) + string(rune('0'+i%10)) }; return s }(); func BenchmarkSlow(b *testing.B) { for i := 0; i < b.N; i++ { ContainsStr(data, "z9") } }; func BenchmarkFast(b *testing.B) { idx := BuildIndex(data); b.ResetTimer(); for i := 0; i < b.N; i++ { ContainsFast(idx, "z9") } }. Run go test -bench=. -benchmem ./... and report the full benchmark output showing ns/op for both. The map lookup should be measurably faster. Report the output.

deadlock-fix|Work in /tmp/training-deadlock/. Run: mkdir -p /tmp/training-deadlock && cd /tmp/training-deadlock && go mod init training/deadlock. Write lock.go: package main; import "sync"; type Cache struct { mu sync.Mutex; data map[string]string }; func NewCache() *Cache { return &Cache{data: map[string]string{}} }; func (c *Cache) Set(k, v string) { c.mu.Lock(); defer c.mu.Unlock(); c.data[k] = v }; func (c *Cache) GetOrSet(k, defaultVal string) string { c.mu.Lock(); defer c.mu.Unlock(); if v, ok := c.data[k]; ok { return v }; c.Set(k, defaultVal); return defaultVal }. Write lock_test.go: package main; import "testing"; func TestGetOrSet(t *testing.T) { c := NewCache(); got := c.GetOrSet("x", "hello"); if got != "hello" { t.Fatalf("got %q", got) } }. Run go test -timeout 5s ./... — it will deadlock and timeout. Identify the deadlock: GetOrSet calls Set while holding the lock. Fix by inlining the set operation inside GetOrSet without calling Set. Run go test ./... to confirm it passes within timeout. Report the timeout error and the fix applied.

binary-reverse-engineer|Work in /tmp/training-reverse/. Run: mkdir -p /tmp/training-reverse && cd /tmp/training-reverse && go mod init training/reverse. Write mystery.go: package main; import "fmt"; func main() { for i := 1; i <= 20; i++ { if i%15==0 { fmt.Println("FizzBuzz") } else if i%3==0 { fmt.Println("Fizz") } else if i%5==0 { fmt.Println("Buzz") } else { fmt.Println(i) } } }. Run go run mystery.go to observe the output. Now write your own implementation in solution.go: package main (in a separate directory /tmp/training-reverse/sol/). Go mod init training/reverse-sol. Write sol.go implementing the same output using a switch statement instead of if-else. Run both programs and diff their outputs: go run /tmp/training-reverse/mystery.go > /tmp/a.txt && go run /tmp/training-reverse/sol/sol.go > /tmp/b.txt && diff /tmp/a.txt /tmp/b.txt. Report that diff produces no output (outputs match).

http-server-debug|Work in /tmp/training-http-debug/. Run: mkdir -p /tmp/training-http-debug && cd /tmp/training-http-debug && go mod init training/http-debug. Write server.go: package main; import ("net/http"; "encoding/json"; "fmt"); func healthHandler(w http.ResponseWriter, r *http.Request) { w.Header().Set("Content-Type", "application/json"); json.NewEncoder(w).Encode(map[string]string{"status": "ok"}) }; func echoHandler(w http.ResponseWriter, r *http.Request) { if r.Method != http.MethodPost { http.Error(w, "method not allowed", http.StatusMethodNotAllowed); return }; var body map[string]any; json.NewDecoder(r.Body).Decode(&body); json.NewEncoder(w).Encode(body) }; func main() { http.HandleFunc("/health", healthHandler); http.HandleFunc("/echo", echoHandler); fmt.Println("listening on :19876"); http.ListenAndServe(":19876", nil) }. Start the server in the background: go run server.go &. Wait 1 second. Curl /health: curl -s http://localhost:19876/health. Curl /echo with POST: curl -s -X POST -H "Content-Type: application/json" -d '{"msg":"hello"}' http://localhost:19876/echo. Then test the bug: curl -s -X GET http://localhost:19876/echo — should return 405. Kill the server (kill %1 or pkill -f server.go). Write server_test.go using net/http/httptest to test all three behaviors. Run go test ./... and report the output.

shell-pipeline-fix|Work in /tmp/training-pipeline/. Run: mkdir -p /tmp/training-pipeline && cd /tmp/training-pipeline. Write process.sh with this broken pipeline: #!/usr/bin/env bash; set -euo pipefail; echo -e "alice 10\nbob 5\ncarol 20\ndave 15" | awk '{print $2, $1}' | sort -k1 -n | awk '{print $2": "$1}' > /tmp/ranked.txt; cat /tmp/ranked.txt. Make it executable: chmod +x process.sh. Run it: ./process.sh. The output should rank users by score ascending (bob:5, alice:10, dave:15, carol:20). However the output format is wrong — it uses ": " but should use " -> ". Fix the second awk statement to print $2" -> "$1. Re-run ./process.sh and verify the output shows: bob -> 5, alice -> 10, dave -> 15, carol -> 20 (one per line). Report the before and after output.

flaky-test-fix|Work in /tmp/training-flaky/. Run: mkdir -p /tmp/training-flaky && cd /tmp/training-flaky && go mod init training/flaky. Write timer.go: package main; import "time"; func SlowOp() string { time.Sleep(50 * time.Millisecond); return "done" }. Write timer_test.go: package main; import ("testing"; "time"); func TestSlowOp(t *testing.T) { start := time.Now(); result := SlowOp(); elapsed := time.Since(start); if elapsed < 40*time.Millisecond { t.Fatalf("too fast: %v", elapsed) }; if elapsed > 60*time.Millisecond { t.Fatalf("too slow: %v", elapsed) }; if result != "done" { t.Fatalf("got %q", result) } }. Run go test ./... five times in a row: for i in 1 2 3 4 5; do go test ./...; done. The test is flaky because the upper bound (60ms) is too tight for CI variability. Fix timer_test.go: change the upper bound check to 200*time.Millisecond to make it robust while still catching real hangs. Run go test ./... five more times to confirm it is now consistently green. Report the runs showing consistency.

json-struct-fix|Work in /tmp/training-json-fix/. Run: mkdir -p /tmp/training-json-fix && cd /tmp/training-json-fix && go mod init training/json-fix. Write types.go: package main; type Response struct { UserID int; UserName string; IsActive bool; CreatedAt string }. Write main.go: package main; import ("encoding/json"; "fmt"; "log"); func main() { raw := []byte(`{"user_id":42,"user_name":"alice","is_active":true,"created_at":"2024-01-15"}`); var r Response; if err := json.Unmarshal(raw, &r); err != nil { log.Fatal(err) }; fmt.Printf("ID=%d Name=%s Active=%v\n", r.UserID, r.UserName, r.IsActive) }. Run go run ./... — the fields will all be zero/empty because the struct has no JSON tags. Add json struct tags to types.go for all four fields (UserID -> user_id, UserName -> user_name, IsActive -> is_active, CreatedAt -> created_at). Run go run ./... again. Report the output before (showing zeros) and after (showing ID=42 Name=alice Active=true).

goroutine-leak-fix|Work in /tmp/training-goroutine-leak/. Run: mkdir -p /tmp/training-goroutine-leak && cd /tmp/training-goroutine-leak && go mod init training/goroutine-leak. Write leak.go: package main; import ("fmt"; "runtime"; "time"); func startWorker() { ch := make(chan int); go func() { val := <-ch; fmt.Println(val) }(); }; func main() { before := runtime.NumGoroutine(); for i := 0; i < 10; i++ { startWorker() }; time.Sleep(10*time.Millisecond); after := runtime.NumGoroutine(); fmt.Printf("before=%d after=%d leaked=%d\n", before, after, after-before) }. Run go run leak.go — it will show leaked goroutines because nobody sends to ch. Fix startWorker: close the channel immediately after creating it so the goroutine unblocks (change the unbuffered channel to a buffered channel of size 1 and send a value, OR use a done channel with close). Specifically: make ch buffered (make(chan int, 1)) and send a value (ch <- 42) before the goroutine reads. Re-run go run leak.go and verify leaked=0. Write leak_test.go: package main; import ("runtime"; "testing"; "time"); func TestNoLeak(t *testing.T) { before := runtime.NumGoroutine(); for i := 0; i < 10; i++ { startWorker() }; time.Sleep(50*time.Millisecond); after := runtime.NumGoroutine(); if after-before > 2 { t.Fatalf("leaked %d goroutines", after-before) } }. Run go test ./... to confirm. Report the before/after outputs.

cgo-build-fix|Work in /tmp/training-cgo-fix/. Run: mkdir -p /tmp/training-cgo-fix && cd /tmp/training-cgo-fix && go mod init training/cgo-fix. Write pure.go: package main; import ("fmt"; "math"); func Hypotenuse(a, b float64) float64 { return math.Sqrt(a*a + b*b) }; func main() { fmt.Printf("%.4f\n", Hypotenuse(3, 4)) }. Write pure_test.go: package main; import ("math"; "testing"); func TestHypotenuse(t *testing.T) { got := Hypotenuse(3, 4); if math.Abs(got-5.0) > 1e-9 { t.Fatalf("got %v", got) } }. Run CGO_ENABLED=0 go test ./... to verify it builds and passes without CGO. Now verify the binary is statically linked: CGO_ENABLED=0 go build -o /tmp/hyp ./... && file /tmp/hyp. The file command should report "statically linked" or "Mach-O" without dynamic linking. Run go test -v ./... and report the full output including the test name and PASS status.
